mapper.select:
SELECT r.*, s.space_code, a.area_code, u.username FROM parking_record r LEFT JOIN parking_space s ON r.space_id = s.space_id LEFT JOIN parking_area a ON s.area_id = a.area_id LEFT JOIN sys_user u ON r.user_id = u.user_id
AND r.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND r.status = #{status}
AND r.pay_status = #{payStatus}
ORDER BY r.create_time DESC
